        var prevLeaf: PsiElement? = this.prevLeaf()
        val iterator = prevLeafs.iterator()
        while (iterator.hasNext()) {
            val psiElement = iterator.next()
            if (psiElement is PsiComment ||
                psiElement.isPartOfComment() || // Added this check
                (psiElement is PsiWhiteSpace && psiElement.text?.count { it == '\n' } == 1)
            ) {
                prevLeaf = psiElement
            } else {
                break
            }
        }
        return prevLeaf
    }

    private fun PsiElement.isPartOfComment(): Boolean {
        var parent = this.parent
        while (parent != null && parent !is PsiFile) {
            if (parent is PsiComment) {
                return true
            }
            parent = parent.parent
        }
        return false
    }
